+    #[test]
+    fn constants_are_sane() {
+        use super::{DEFAULT_STATE_DIR, DOWNLOAD_TIMEOUT, FFMPEG_TOOLS_DIR};
+        assert!(!DEFAULT_STATE_DIR.is_empty());
+        assert!(!FFMPEG_TOOLS_DIR.is_empty());
+        assert!(DOWNLOAD_TIMEOUT.as_secs() > 0);
+    }
